import { useEffect } from "react"
import "./news.css"
import { useRef } from "react"
import { useState } from "react"
function News() {
    let ref = useRef([])
    const interests = [
        "Business",
        "Entertainment",
        "General",
        "Health",
        "Science",
        "Sports",
        "Technology"
    ]
    let [selecteditems, changeselected] = useState([])
    useEffect(() => { //in the future when the user chooses to go to news, check if they have completed the form, if yes then re-reoute to other component with news
        async function datafromback() {
            let res = await fetch("http://localhost:5000/intereststatusnews", {
                method: "GET",
                headers: { "Content-Type": "application/json" },
                credentials: "include",
            })
            console.log(selecteditems)
        }
        datafromback()
    }, [selecteditems])
    function clickinterests(index) {
        changeselected([...selecteditems, ref.current.map((item, indexitem) => {
            if(index == indexitem) {
                console.log(item)
                if(item.style.borderColor == "rgba(90, 180, 255, 0.9)") {
                    item.style.border = "1px solid rgba(48, 95, 200, 0.45)"
                    item.style.boxShadow = "none"
                }
                else {
                    item.style.borderColor = "rgba(90, 180, 255, 0.9)"
                    item.style.boxShadow = "0 0 12px rgba(70, 150, 255, 0.35)"
                }
                return item.textContent
            }
        }).filter((item) => {
            console.log(item)
            return item !== selecteditems[index] && item !== undefined
        })[0]])
    }
    function continuebtn() {

    }
    return<>
        <div className="interest-page">
        <div className="interest-bg-left"></div>
        <div className="interest-bg-center"></div>
        <div className="interest-bg-right"></div>

        <div className="interest-container">
            <div className="interest-header">
            <h1>Select Your Interests</h1>
            <p>Choose topics you want to see in your feed</p>
            </div>

            <div className="interest-grid">
            {interests.map((interest, index) => (
                <div
                    key={index}
                    className="interest-card"
                    ref={(el) => (ref.current[index] = el)}
                    onClick={() => clickinterests(index)}
                    >
                    {interest}
                     </div>
            ))}
            </div>

            <button onClick={() => continuebtn()} className="interest-button">Continue</button>
        </div>
        </div>
    </>
}
export default News
